    // Left[node] == -1 means leaf node
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static double Eval(int node, ReadOnlySpan<double> f)
    {
        while (true)
        {
            if (Left[node] < 0)
                return Value[node];
            double v = f[Feature[node]];
            if (double.IsNaN(v))
                node = Missing[node];
            else if ((float)v < Threshold[node])
                node = Left[node];
            else
                node = Right[node];
        }
    }

